Information_Elements.IE_Definition:
UEContextSetupRequestIEs F1AP-PROTOCOL-IES ::= {
    { ID id-LTMConfigurationIDMappingList         CRITICALITY reject   TYPE LTMConfigurationIDMappingList         PRESENCE optional },
    { ID id-CSIResourceConfigurationforLTM      CRITICALITY reject   TYPE CSIResourceConfigurationforLTM      PRESENCE optional },
    { ID id-CandidateCellID                      CRITICALITY reject   TYPE CellID                              PRESENCE mandatory },
    { ID id-PRACHResources                       CRITICALITY reject   TYPE PRACHResources                      PRESENCE optional },
    { ID id-LowerLayerConfiguration              CRITICALITY reject   TYPE LowerLayerConfiguration             PRESENCE optional }
}

LTMConfigurationIDMappingItem ::= SEQUENCE {
    lTMConfigurationID        LTMConfigurationID,
    lTMConfigurationIDMapping LTMConfigurationIDMapping
}

CSIResourceConfigurationforLTM ::= SEQUENCE {
    csi-RS-ResourceConfigId   CSI-RS-ResourceConfigId,
    csi-RS-ResourceConfig     CSI-RS-ResourceConfig
}

PRACHResources ::= SEQUENCE {
    prach-ConfigurationIndex  PRACH-ConfigurationIndex,
    prach-FrequencyOffset     PRACH-FrequencyOffset
}

UEContextSetupResponseIEs F1AP-PROTOCOL-IES ::= {
    { ID id-GeneratedLowerLayerRRCConfigurations CRITICALITY reject   TYPE GeneratedLowerLayerRRCConfigurations PRESENCE optional },
    { ID id-AcceptedTargetCellID                  CRITICALITY reject   TYPE CellID                               PRESENCE mandatory }
}
